"""Generate README.chromium files for each crate under vendor/.

For every crate directory, writes:
  vendor/<crate>/README.chromium

containing Chromium-style license metadata that `tools/licenses.py` can
discover and include in about_credits.html.

The top-level crate `boringtun` is skipped -- it is already covered by
brave/third_party/boringtun/README.chromium at the parent level.

License selection rules:
  * Single license:    use the one license file.
  * "A OR B":          prefer MIT, fall back to Apache, else the first
                       file present.
  * "A AND B":         generate a combined attribution file concatenating
                       both originals, and point License File: at it
                       (named just LICENSE when that path is free, else
                       LICENSE-combined-brave-attribution).
  * "(A OR B) AND C":  pick one of (A, B) by OR preference, then combine
                       with C as above.
  * If license is MIT but no MIT file is present in the crate, an MIT
                       file is synthesized from the crate's authors/year
                       and written as LICENSE (with a warning -- this is
                       an upstream packaging bug being papered over).

When the resolved license file is named exactly LICENSE, the
'License File:' line is omitted from README.chromium; Chromium's license
tooling finds a sibling LICENSE automatically.

Re-run behavior: if README.chromium already exists, the script merges:
  * Version:           auto-updated to match the current Cargo.toml.
  * Description, Local Modifications, Security Critical, Shipped:
                       preserved from the existing file if present.
  * Name, Short Name, URL, License, License File:
                       validated against the computed value; any
                       mismatch is flagged as drift and exits non-zero.

Run this AFTER `cargo vendor` and commit the resulting files.
Re-run on every BoringTun pin bump.
"""

import argparse
import re
import sys
from pathlib import Path
from typing import Optional

try:
    import tomllib  # Python 3.11+
except ModuleNotFoundError:
    import tomli as tomllib  # type: ignore

LICENSE_NAME_PREFIXES = ('LICENSE', 'LICENCE', 'COPYING', 'NOTICE',
                         'UNLICENSE')

# Path under src/ that License File: entries are rooted at. Chromium's
# license tool resolves `License File:` relative to the README.chromium's
# own directory, so these are just plain filenames in most cases.
# We emit relative paths.

# Chromium's license-attribution tool falls back to a sibling file named
# exactly 'LICENSE' when README.chromium has no 'License File:' line. We
# exploit that: whenever the file we'd point at is named 'LICENSE', we
# omit the field. When generating a file ourselves (synthesized MIT or
# combined attribution) we prefer this name so the field can be omitted,
# falling back to a longer name only when an upstream file already
# occupies the path.
DEFAULT_LICENSE_FILENAME = 'LICENSE'

# Fallback name for the combined attribution file when 'LICENSE' is
# already taken by an upstream file we can't overwrite.
COMBINED_FILENAME = 'LICENSE-combined-brave-attribution'

# First line of every attribution file we generate. Doubles as a sentinel
# so a re-run can tell its own previously-written 'LICENSE' apart from
# one shipped by upstream and avoid double-counting it as a real source
# of license text.
GENERATED_MARKER = 'This file is generated by create_licenses.py.'

# Crate names to skip entirely. The top-level boringtun crate is already
# covered by brave/third_party/boringtun/README.chromium at the parent.
SKIP_CRATES = {'boringtun'}

# MIT license text below is the canonical OSI template, reproduced from
# https://opensource.org/license/mit. The {year} and {holder} braces are
# Python str.format placeholders inserted by synthesize_mit_license; they
# are not part of the upstream license text.
MIT_TEMPLATE = """\
MIT License

Copyright (c) {year} {holder}

Permission is hereby granted, free of charge, to any person obtaining a copy
of this software and associated documentation files (the "Software"), to deal
in the Software without restriction, including without limitation the rights
to use, copy, modify, merge, publish, distribute, sublicense, and/or sell
copies of the Software, and to permit persons to whom the Software is
furnished to do so, subject to the following conditions:

The above copyright notice and this permission notice shall be included in all
copies or substantial portions of the Software.

THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR
IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,
FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE
AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER
LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,
OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE
SOFTWARE.
"""

COMBINED_HEADER = GENERATED_MARKER + """

This crate is licensed under the SPDX expression:
    {spdx}

Both licenses apply simultaneously. The original files are preserved in
this directory unchanged; this combined file exists only to give the
Chromium license-attribution tooling a single file to point at.

Section markers below indicate which original file each block came from.

"""

# Fields whose drift from the computed value is noise (reviewer-owned)
# and should be preserved across regeneration.
PRESERVED_FIELDS = {
    'Description', 'Local Modifications', 'Security Critical', 'Shipped'
}

# Fields that MUST match between existing and computed; drift here means
# upstream changed something license-relevant and needs review.
VALIDATED_FIELDS = {'Name', 'Short Name', 'URL', 'License', 'License File'}

# Fields we silently auto-update to the computed value.
AUTO_UPDATE_FIELDS = {'Version'}


def is_license_file(name: str) -> bool:
    upper = name.upper()
    for prefix in LICENSE_NAME_PREFIXES:
        if upper == prefix:
            return True
        if upper.startswith(prefix + '.') or upper.startswith(prefix + '-'):
            return True
    return False


def is_generated_combined(path: Path) -> bool:
    """Return True if `path` is a combined-attribution file we wrote.

    Detected by looking for GENERATED_MARKER on the first line. Used in
    license discovery so that on a re-run we don't mistake our own
    previously-generated 'LICENSE' for one shipped by upstream -- which
    would skip the combine step and silently lose attribution for one of
    the AND-ed licenses.
    """
    try:
        with path.open('r', encoding='utf-8', errors='replace') as f:
            first_line = f.readline().rstrip('\n')
    except OSError:
        return False
    return first_line == GENERATED_MARKER


# Filenames previous versions of this script wrote for synthesized MIT
# and combined attribution. Kept here so re-runs after the migration to
# 'LICENSE' don't accidentally pick them up as upstream license sources.
# New runs no longer create files at these paths; existing files at
# these paths from older runs are stale and can be deleted by hand.
LEGACY_GENERATED_NAMES = {
    COMBINED_FILENAME,
    'LICENSE-MIT-brave-attribution',
}


def find_license_files(crate_dir: Path) -> list[Path]:
    """Sorted list of license-ish file paths at the top of crate_dir.

    Excludes files we generated on a previous run -- by legacy filename
    and by content marker -- so re-running is idempotent and a generated
    'LICENSE' isn't double-counted as upstream-shipped.
    """
    return sorted(
        entry for entry in crate_dir.iterdir()
        if entry.is_file() and is_license_file(entry.name) and entry.name
        not in LEGACY_GENERATED_NAMES and not is_generated_combined(entry))


def combined_output_name(crate_dir: Path) -> str:
    """Pick a filename for the combined attribution file in this crate.

    Prefer DEFAULT_LICENSE_FILENAME so the README.chromium can omit the
    'License File:' line entirely. Fall back to COMBINED_FILENAME only
    when an upstream file already occupies the 'LICENSE' path -- our own
    previously-generated 'LICENSE' (identified by GENERATED_MARKER) does
    not count as a conflict and will simply be overwritten.
    """
    target = crate_dir / DEFAULT_LICENSE_FILENAME
    if not target.exists() or is_generated_combined(target):
        return DEFAULT_LICENSE_FILENAME
    return COMBINED_FILENAME


def make_combined_license(crate_dir: Path,
                          files: list[Path],
                          spdx: str,
                          output_name: str = COMBINED_FILENAME,
                          dry_run: bool = False) -> Path:
    """
    Concatenate `files` with separator markers into `output_name` under
    crate_dir.

    Returns the path. In dry-run mode, returns the path without writing.
    """
    out = crate_dir / output_name
    if dry_run:
        return out
    parts = [COMBINED_HEADER.format(spdx=spdx)]
    for f in files:
        parts.append('=' * 78)
        parts.append(f'Original file: {f.name}')
        parts.append('=' * 78)
        parts.append('')
        parts.append(f.read_text(encoding='utf-8', errors='replace'))
        parts.append('')
    out.write_text('\n'.join(parts), encoding='utf-8')
    return out


def tokenize_spdx(expr: str) -> list[str]:
    """Tokenize an SPDX expression into: IDs, OR, AND, WITH, '(', ')'.

    We treat a multi-word ID like 'Apache-2.0 WITH LLVM-exception' as a
    single token by joining 'WITH <id>' back onto the preceding ID.
    """
    # Insert spaces around parentheses so split() handles them.
    s = expr.replace('(', ' ( ').replace(')', ' ) ')
    raw = s.split()
    tokens: list[str] = []
    i = 0
    while i < len(raw):
        tok = raw[i]
        if tok in ('(', ')', 'OR', 'AND'):
            tokens.append(tok)
            i += 1
            continue
        # Identifier. Consume any following 'WITH <id>' as part of it.
        ident = tok
        while (i + 2 < len(raw) and raw[i + 1] == 'WITH'
               and raw[i + 2] not in ('(', ')', 'OR', 'AND')):
            ident = f'{ident} WITH {raw[i + 2]}'
            i += 2
        tokens.append(ident)
        i += 1
    return tokens


def parse_spdx_expr(tokens: list[str]) -> dict:
    """Parse tokens into a tree of {op: 'or'|'and'|'id', ...}.

    Grammar (simplified; no precedence beyond parens):
        expr   := and_expr
        and_expr := or_expr (AND or_expr)*
        or_expr  := atom (OR atom)*
        atom     := IDENT | '(' expr ')'

    Real SPDX gives AND tighter precedence than OR, but in practice
    crates write explicit parens when they want precedence to matter,
    and we follow SPDX by binding AND tighter. We accept but don't
    require parens.
    """
    pos = [0]  # Boxed index so nested calls can mutate.

    def peek():
        return tokens[pos[0]] if pos[0] < len(tokens) else None

    def consume():
        t = tokens[pos[0]]
        pos[0] += 1
        return t

    def parse_atom() -> dict:
        t = peek()
        if t == '(':
            consume()
            node = parse_or()
            if peek() != ')':
                raise ValueError(f'missing ) in {tokens}')
            consume()
            return node
        if t is None or t in ('OR', 'AND', ')'):
            raise ValueError(f'unexpected token {t!r} in {tokens}')
        return {'op': 'id', 'value': consume()}

    def parse_and() -> dict:
        # AND is tighter than OR: chain of atoms joined by AND.
        left = parse_atom()
        while peek() == 'AND':
            consume()
            right = parse_atom()
            if left['op'] == 'and':
                left['terms'].append(right)
            else:
                left = {'op': 'and', 'terms': [left, right]}
        return left

    def parse_or() -> dict:
        left = parse_and()
        while peek() == 'OR':
            consume()
            right = parse_and()
            if left['op'] == 'or':
                left['terms'].append(right)
            else:
                left = {'op': 'or', 'terms': [left, right]}
        return left

    tree = parse_or()
    if pos[0] != len(tokens):
        raise ValueError(f'trailing tokens: {tokens[pos[0]:]}')
    return tree


def reduce_spdx(tree: dict) -> list[str]:
    """Apply OR-preference to pick a final list of licenses to attribute.

    For OR nodes, pick the single best branch (MIT > Apache > BSD > ISC
    > first). For AND nodes, keep all branches. Single IDs pass through.

    Returns a flat list of SPDX ID strings that collectively represent
    what we must attribute for the crate.
    """
    op = tree['op']
    if op == 'id':
        return [tree['value']]
    if op == 'and':
        out = []
        for t in tree['terms']:
            out.extend(reduce_spdx(t))
        return out
    if op == 'or':
        # Reduce each branch first, then pick the branch containing the
        # most-preferred ID. This handles nested cases like
        # "(MIT OR Apache-2.0) AND Unicode-DFS-2016" correctly.
        reduced = [reduce_spdx(t) for t in tree['terms']]
        preference = ('MIT', 'APACHE', 'BSD', 'ISC')
        for keyword in preference:
            for branch in reduced:
                for ident in branch:
                    if keyword in ident.upper():
                        return branch
        return reduced[0]
    raise ValueError(f'unknown op {op!r}')


def parse_spdx(expr: str) -> list[str]:
    """Parse an SPDX expression and apply OR-preference.

    Returns the list of license IDs that must be attributed for the
    crate, or [] if parsing failed.
    """
    try:
        tokens = tokenize_spdx(expr)
        tree = parse_spdx_expr(tokens)
        return reduce_spdx(tree)
    except (ValueError, IndexError):
        return []


def build_url(pkg: dict) -> str:
    """Best-effort canonical URL for a crate."""
    for key in ('repository', 'homepage', 'documentation'):
        val = pkg.get(key)
        if val:
            return val
    return f'https://crates.io/crates/{pkg.get("name", "")}'


def looks_like_field_header(line: str) -> Optional[tuple[str, str]]:
    """Return (key, value) if line is a "Key: value" header, else None.

    Key must start with an ASCII letter and contain only ASCII letters
    and spaces (matches Chromium README.chromium field naming).
    """
    if ':' not in line:
        return None
    key, _, value = line.partition(':')
    if not key or not key[0].isascii() or not key[0].isalpha():
        return None
    if not all((c.isascii() and c.isalpha()) or c == ' ' for c in key):
        return None
    return key.strip(), value.strip()


def parse_readme(path: Path) -> tuple[dict, dict]:
    """Parse a README.chromium into (fields, sections).

    Fields are "Key: Value" lines at the top of the file. Sections are
    multi-line blocks keyed by "Key:\\nvalue lines..." (Description,
    Local Modifications). Returns empty dicts if the file doesn't parse
    cleanly -- we treat unparseable as "regenerate from scratch."
    """
    fields: dict[str, str] = {}
    sections: dict[str, str] = {}

    text = path.read_text(encoding='utf-8', errors='replace')
    lines = text.splitlines()

    i = 0
    while i < len(lines):
        line = lines[i]
        if not line.strip():
            i += 1
            continue

        parsed = looks_like_field_header(line)
        if parsed is None:
            break
        key, value = parsed

        # Section headers look like "Description:" with content on
        # following lines, not "Key: Value" on one line.
        if value == '' and key in {'Description', 'Local Modifications'}:
            i += 1
            body_lines = []
            while i < len(lines):
                if looks_like_field_header(lines[i]) is not None:
                    break
                body_lines.append(lines[i])
                i += 1
            sections[key] = '\n'.join(body_lines).strip()
        else:
            fields[key] = value
            i += 1

    return fields, sections


def format_readme(fields: dict, sections: dict) -> str:
    """Format fields + sections back into a README.chromium string."""
    # Preserve a canonical field order for readability.
    order = [
        'Name', 'Short Name', 'URL', 'Version', 'License', 'License File',
        'Security Critical', 'Shipped'
    ]
    lines = []
    for key in order:
        if key in fields:
            lines.append(f'{key}: {fields[key]}')
    # Any unexpected fields appended at the end, preserving them.
    for key in fields:
        if key not in order:
            lines.append(f'{key}: {fields[key]}')
    for key in ('Description', 'Local Modifications'):
        if key in sections:
            lines.append('')
            lines.append(f'{key}:')
            lines.append(sections[key])
    return '\n'.join(lines) + '\n'


def strip_email(s: str) -> str:
    """Remove an <email@host> substring from an author line."""
    start = s.find('<')
    end = s.find('>', start + 1) if start != -1 else -1
    if start != -1 and end != -1:
        return (s[:start] + s[end + 1:]).strip()
    return s.strip()


def synthesize_mit_license(crate_dir: Path,
                           pkg: dict,
                           dry_run: bool = False) -> Path:
    """Generate a LICENSE file for this crate from MIT_TEMPLATE.

    Uses the crate's `authors` field as the copyright holder. This is a
    best-effort fallback for crates that declare MIT but ship no license
    file -- an upstream packaging bug we paper over.

    Writes to DEFAULT_LICENSE_FILENAME ('LICENSE') so the README.chromium
    can omit 'License File:' entirely. Picking that name unconditionally
    is safe here: this function is only called when find_license_files()
    returned empty, which means no upstream LICENSE/COPYING/etc. file
    exists in the crate to clash with.

    In dry-run mode, returns the path without writing.
    """
    out = crate_dir / DEFAULT_LICENSE_FILENAME
    if out.exists() or dry_run:
        return out

    authors = pkg.get('authors') or []
    if isinstance(authors, list):
        names = [strip_email(a) for a in authors]
        holder = ', '.join(n for n in names if n) or 'the crate authors'
    else:
        holder = str(authors) or 'the crate authors'

    from datetime import datetime
    year = datetime.now().year

    out.write_text(MIT_TEMPLATE.format(year=year, holder=holder),
                   encoding='utf-8')
    return out


def pick_license_file_for_id(spdx_id: str,
                             files: list[Path]) -> Optional[Path]:
    """Return the license file whose name best matches a single SPDX id."""
    upper_id = spdx_id.upper()
    # Direct keyword matches, most specific first.
    keywords = []
    if 'MIT' in upper_id:
        keywords.append('MIT')
    if 'APACHE' in upper_id:
        keywords.append('APACHE')
    if 'BSD' in upper_id:
        keywords.append('BSD')
    if 'ISC' in upper_id:
        keywords.append('ISC')
    if 'UNICODE' in upper_id:
        keywords.append('UNICODE')
    for kw in keywords:
        for f in files:
            if kw in f.name.upper():
                return f
    return None


def compute_readme(
        crate_dir: Path,
        dry_run: bool = False) -> tuple[dict, dict, bool, list[str]]:
    """Compute fresh README fields + sections for one crate.

    Returns (fields, sections, had_problem, warnings).

    Resolution logic for License File:
      * If `license-file` is declared in Cargo.toml, trust it.
      * Else, parse the SPDX expression into the list of IDs we must
        attribute (after applying OR-preference).
      * For each ID, try to find a file whose name matches the ID.
      * If no file matches AND there are zero license files at all AND
        the ID is MIT, synthesize an MIT file from a template.
      * If file-by-name lookup fails but license files ARE present,
        fall back to using the present files. This covers two real
        cases: a single-license crate whose only file is named LICENSE
        (e.g. nu-ansi-term -> MIT), and an AND-licensed crate that
        bundled both texts into one file (e.g. ring -> Apache+ISC).
    """
    warnings: list[str] = []
    cargo_toml = crate_dir / 'Cargo.toml'
    if not cargo_toml.is_file():
        return ({}, {}, True, [f'{crate_dir.name}: no Cargo.toml'])

    with cargo_toml.open('rb') as f:
        data = tomllib.load(f)
    pkg = data.get('package', {})

    name = pkg.get('name', crate_dir.name)
    version = pkg.get('version', '').split('+', 1)[0]
    license_expr = pkg.get('license', '').strip()
    license_file_field = pkg.get('license-file', '').strip()
    url = build_url(pkg)

    files = find_license_files(crate_dir)
    problem = False
    license_file_entry = ''

    if license_file_field:
        license_file_entry = license_file_field
        if not (crate_dir / license_file_field).is_file():
            license_file_entry = f'ToDo(declared {license_file_field} missing)'
            problem = True
    elif not license_expr:
        license_file_entry = 'ToDo(no license field)'
        problem = True
    else:
        ids = parse_spdx(license_expr)
        if not ids:
            license_file_entry = f'ToDo(unparsable SPDX: {license_expr})'
            problem = True
        else:
            # Try to map each required id to a specific file by name.
            matched: list[Path] = []
            unmatched_ids: list[str] = []
            for spdx_id in ids:
                picked = pick_license_file_for_id(spdx_id, files)
                if picked is not None:
                    matched.append(picked)
                else:
                    unmatched_ids.append(spdx_id)

            if not unmatched_ids:
                # Every id mapped to a file. Use them.
                if len(matched) == 1:
                    license_file_entry = matched[0].name
                else:
                    combined = make_combined_license(
                        crate_dir,
                        matched,
                        license_expr,
                        output_name=combined_output_name(crate_dir),
                        dry_run=dry_run)
                    license_file_entry = combined.name
            elif files:
                # Some id didn't match by name, but files are present.
                # Trust whatever upstream shipped: for one file, use it;
                # for many, combine them all.
                if len(files) == 1:
                    license_file_entry = files[0].name
                else:
                    combined = make_combined_license(
                        crate_dir,
                        files,
                        license_expr,
                        output_name=combined_output_name(crate_dir),
                        dry_run=dry_run)
                    license_file_entry = combined.name
            elif unmatched_ids == ids and len(
                    ids) == 1 and 'MIT' in ids[0].upper():
                # No files at all, and the (single) declared license is
                # MIT. Synthesize from template.
                synth = synthesize_mit_license(crate_dir, pkg, dry_run=dry_run)
                license_file_entry = synth.name
                warnings.append(
                    f'{crate_dir.name}: declared {ids[0]} but shipped no '
                    f'license file -- synthesized {synth.name} from template')
            else:
                license_file_entry = (
                    f'ToDo(no license files present for {license_expr})')
                problem = True

    fields = {
        'Name': name,
        'Short Name': name,
        'URL': url,
        'Version': version,
        'License': license_expr if license_expr else 'ToDo',
    }
    # Omit 'License File:' when we'd point at the Chromium-default
    # filename: the license tool finds a sibling LICENSE automatically.
    # ToDo markers (and any other non-default name) are kept so a human
    # can still see what's wrong.
    if license_file_entry and license_file_entry != DEFAULT_LICENSE_FILENAME:
        fields['License File'] = license_file_entry
    sections = {
        'Description': (
            f'Transitive dependency of BoringTun, vendored under\n'
            f'brave/third_party/boringtun/vendor/{crate_dir.name}.'),
        'Local Modifications': (
            'None. Source vendored via `cargo vendor` from crates.io at '
            'the version\npinned by brave/third_party/boringtun/Cargo.lock.'),
    }
    return (fields, sections, problem, warnings)


def merge_with_existing(existing_fields: dict, existing_sections: dict,
                        computed_fields: dict, computed_sections: dict,
                        crate_name: str) -> tuple[dict, dict, list[str]]:
    """Merge computed values into an existing README.

    Rules:
      * VALIDATED_FIELDS: existing must match computed, else record drift.
      * AUTO_UPDATE_FIELDS: always take computed value.
      * PRESERVED_FIELDS: keep existing value if present.

    Returns (merged_fields, merged_sections, drifts) where drifts is a
    list of human-readable strings describing unexpected changes.
    """
    drifts = []
    merged: dict[str, str] = dict(computed_fields)

    for key in VALIDATED_FIELDS:
        old = existing_fields.get(key)
        new = computed_fields.get(key)
        if old is not None and new is not None and old != new:
            drifts.append(f'  {crate_name}: {key!r} changed '
                          f'{old!r} -> {new!r}')

    for key in AUTO_UPDATE_FIELDS:
        if key in computed_fields:
            merged[key] = computed_fields[key]

    for key in PRESERVED_FIELDS:
        if key in existing_fields:
            merged[key] = existing_fields[key]

    # Sections: preserve reviewer edits. If the existing section text
    # differs from computed, keep the existing one (it may contain
    # reviewer-added notes we don't want to lose).
    merged_sections = dict(computed_sections)
    for key in ('Description', 'Local Modifications'):
        if key in existing_sections and existing_sections[key]:
            merged_sections[key] = existing_sections[key]

    return merged, merged_sections, drifts


def main():
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument(
        '--vendor',
        type=Path,
        default=(Path(__file__).resolve().parent / 'vendor'),
        help='Path to vendor/. Defaults to "vendor/" relative to this script.')
    ap.add_argument(
        '--dry-run',
        action='store_true',
        help='Print what would be written without modifying anything.')
    args = ap.parse_args()

    if not args.vendor.is_dir():
        sys.exit(f'vendor dir not found: {args.vendor}')

    written = 0
    skipped = []
    problems = []
    drifts = []
    warnings = []

    for crate_dir in sorted(p for p in args.vendor.iterdir() if p.is_dir()):
        if crate_dir.name in SKIP_CRATES:
            skipped.append(crate_dir.name)
            continue

        computed_fields, computed_sections, had_problem, crate_warnings = \
            compute_readme(crate_dir, dry_run=args.dry_run)
        warnings.extend(crate_warnings)
        if not computed_fields:
            problems.append(crate_dir.name)
            continue

        readme_path = crate_dir / 'README.chromium'
        if readme_path.is_file():
            existing_fields, existing_sections = parse_readme(readme_path)
            final_fields, final_sections, crate_drifts = merge_with_existing(
                existing_fields, existing_sections, computed_fields,
                computed_sections, crate_dir.name)
            drifts.extend(crate_drifts)
        else:
            final_fields = computed_fields
            final_sections = computed_sections

        readme_text = format_readme(final_fields, final_sections)

        if args.dry_run:
            print(f'--- {readme_path} ---')
            print(readme_text)
        else:
            readme_path.write_text(readme_text, encoding='utf-8')
            written += 1

        if had_problem:
            problems.append(crate_dir.name)

    if args.dry_run:
        total = sum(1 for p in args.vendor.iterdir()
                    if p.is_dir() and p.name not in SKIP_CRATES)
        print(f'\n(dry-run) would process {total} crates', file=sys.stderr)
    else:
        print(f'Wrote {written} README.chromium files', file=sys.stderr)

    if skipped:
        print(f'Skipped {len(skipped)} crate(s): {", ".join(skipped)}',
              file=sys.stderr)

    if warnings:
        print(f'\n{len(warnings)} warning(s):', file=sys.stderr)
        for w in warnings:
            print(f'  {w}', file=sys.stderr)

    if drifts:
        print(f'\n{len(drifts)} drift(s) vs existing README.chromium:',
              file=sys.stderr)
        for d in drifts:
            print(d, file=sys.stderr)
        print(
            '\nThese fields changed between the existing README and what '
            'the Cargo.toml / license files currently say. Review each one '
            '-- most likely the crate upstream changed license, URL, or '
            'name, and attribution needs a human eye.',
            file=sys.stderr)

    if problems:
        print(
            f'\n{len(problems)} crates need human review '
            f'(ToDo markers in README.chromium):',
            file=sys.stderr)
        for name in problems:
            print(f'  - {name}', file=sys.stderr)

    if drifts or problems:
        sys.exit(1)


if __name__ == '__main__':
    main()
